"use strict";(globalThis.webpackChunkdocumentation=globalThis.webpackChunkdocumentation||[]).push([[130],{7735:e=>{e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/blog/welcome","editUrl":"https://github.com/surajmgr/nexus/tree/main/packages/create-docusaurus/templates/shared/blog/2025-12-03-welcome/index.md","source":"@site/blog/2025-12-03-welcome/index.md","title":"Welcome","description":"Welcome to myself, I guess. This page just outlines some standard of writing blog posts in this nexus. Before that, this is built with Docusaurus.","date":"2025-12-03T00:00:00.000Z","tags":[{"inline":false,"label":"Nexus","permalink":"/blog/tags/nexus","description":"Post related to Nexus"},{"inline":false,"label":"General","permalink":"/blog/tags/general","description":"Post related to general topics"},{"inline":false,"label":"How To","permalink":"/blog/tags/how-to","description":"Post related to how to do something"}],"readingTime":1.09,"hasTruncateMarker":true,"authors":[{"name":"Suraj Pulami","title":"Owner of Nexus","url":"https://surajpulami.com.np","page":{"permalink":"/blog/authors/surajmgr"},"socials":{"linkedin":"https://www.linkedin.com/in/surajpulami/","github":"https://github.com/surajmgr"},"imageURL":"/authors/surajmgr.png","key":"surajmgr"}],"frontMatter":{"slug":"welcome","title":"Welcome","authors":["surajmgr"],"tags":["nexus","general","how-to"]},"unlisted":false},"content":"Welcome to myself, I guess. This page just outlines some standard of writing blog posts in this nexus. Before that, this is built with Docusaurus.\\n\\n\x3c!-- truncate --\x3e\\n\\nTo add a new blog post, simply add a new Markdown file to the `blog` directory or a folder in the `blog` directory with `index.md` file. The date of the blog post can be extracted from the filename, such as `2025-12-03-welcome.md` or `2025-12-03-welcome/index.md`.\\n\\nTo add a new author, simply add a new YAML configuration to the `authors.yml` file.\\n\\nAs for the images and styles, you can use the same as in Markdown files.\\n\\nFor configuing this blog post itself, you have to edit the metadata at the top of the file. The metadata is in YAML format and is denoted by `---` at the top and bottom of the file.\\nHere are some of the metadata fields:\\n\\n- `slug`: The slug of the blog post. This is the URL of the blog post.\\n- `title`: The title of the blog post.\\n- `authors`: The authors of the blog post. This is an array of author slugs.\\n- `tags`: The tags of the blog post. This is an array of tag slugs.\\n\\n**And if you don\'t want a blog**: just delete this directory, and use `blog: false` in Docusaurus config."}]}}')}}]);